import{_ as o,o as a,c,a3 as t}from"./chunks/framework.aYYe0dfI.js";const h=JSON.parse('{"title":"Module network","description":"network 模块是 clore 库中负责 LLM（大语言模型）网络通信的核心。它封装了与 OpenAI 和 Anthropic 等提供者的异步交互，对外提供三个主要接口：validate_llm_provider_environment 用于校验运行时环境（如 API 密钥和基础 URL 等必要配置是否完备）；call_llm_async 用于发起针对 LLM 服务的异步请求；call_completion_async 用于发起异步完成调用。所有异步操作均基于 kota::event_loop 驱动，调用方需保证事件循环在操作期间持续有效。","frontmatter":{"title":"Module network","description":"network 模块是 clore 库中负责 LLM（大语言模型）网络通信的核心。它封装了与 OpenAI 和 Anthropic 等提供者的异步交互，对外提供三个主要接口：validate_llm_provider_environment 用于校验运行时环境（如 API 密钥和基础 URL 等必要配置是否完备）；call_llm_async 用于发起针对 LLM 服务的异步请求；call_completion_async 用于发起异步完成调用。所有异步操作均基于 kota::event_loop 驱动，调用方需保证事件循环在操作期间持续有效。","layout":"doc","template":"doc"},"headers":[],"relativePath":"zh/clore/modules/network/index.md","filePath":"zh/clore/modules/network/index.md"}'),r={name:"zh/clore/modules/network/index.md"};function d(l,e,n,i,s,p){return a(),c("div",null,[...e[0]||(e[0]=[t('<h1 id="module-network" tabindex="-1">Module <code>network</code> <a class="header-anchor" href="#module-network" aria-label="Permalink to &quot;Module `network`&quot;">​</a></h1><h2 id="summary" tabindex="-1">Summary <a class="header-anchor" href="#summary" aria-label="Permalink to &quot;Summary&quot;">​</a></h2><p><code>network</code> 模块是 <code>clore</code> 库中负责 LLM（大语言模型）网络通信的核心。它封装了与 <code>OpenAI</code> 和 Anthropic 等提供者的异步交互，对外提供三个主要接口：<code>validate_llm_provider_environment</code> 用于校验运行时环境（如 API 密钥和基础 URL 等必要配置是否完备）；<code>call_llm_async</code> 用于发起针对 LLM 服务的异步请求；<code>call_completion_async</code> 用于发起异步完成调用。所有异步操作均基于 <code>kota::event_loop</code> 驱动，调用方需保证事件循环在操作期间持续有效。</p><p>模块内部通过匿名命名空间中的辅助函数（如 <code>detect_provider_from_environment</code>、<code>dispatch_completion</code> 等）实现提供者自动检测、环境变量解析以及完成回调的分发。它维护了 <code>Provider</code> 枚举类型和相关的环境变量常量，确保在调用外部 LLM 服务之前能够正确识别和配置目标提供者。整体上，该模块抽象了不同 LLM 提供者的网络调用差异，为上层代码提供了一个简洁、一致的异步网络交互层。</p><h2 id="imports" tabindex="-1">Imports <a class="header-anchor" href="#imports" aria-label="Permalink to &quot;Imports&quot;">​</a></h2><ul><li><code>std</code></li></ul><h2 id="imported-by" tabindex="-1">Imported By <a class="header-anchor" href="#imported-by" aria-label="Permalink to &quot;Imported By&quot;">​</a></h2><ul><li><a href="./../agent/"><code>agent</code></a></li><li><a href="./../generate/scheduler"><code>generate:scheduler</code></a></li></ul><h2 id="functions" tabindex="-1">Functions <a class="header-anchor" href="#functions" aria-label="Permalink to &quot;Functions&quot;">​</a></h2><h3 id="clore-net-call-completion-async" tabindex="-1"><code>clore::net::call_completion_async</code> <a class="header-anchor" href="#clore-net-call-completion-async" aria-label="Permalink to &quot;`clore::net::call_completion_async`&quot;">​</a></h3><p>Declaration: <code>network/network.cppm:24</code></p><p>Definition: <code>network/network.cppm:150</code></p><p>Declaration: <a href="./../../namespaces/clore/net/"><code>Namespace clore::net</code></a></p><p>函数 <code>clore::net::call_completion_async</code> 的实现采用两步委托模式：首先通过 <code>detect_provider_from_environment</code> 从环境变量（如 <code>kAnthropicApiKeyEnv</code>、<code>kOpenAIApiKeyEnv</code> 等）推断出 <code>Provider</code> 枚举值；若提供商检测失败，则通过 <code>kota::fail</code> 直接返回错误。成功后，将 <code>provider</code>、原始 <code>request</code> 和 <code>loop</code> 转发给 <code>dispatch_completion</code>，该函数内部根据 <code>Provider</code> 类型（如 <code>Anthropic</code> 或 <code>OpenAI</code>）调用对应的 <code>request_provider_text_async</code> 或 <code>call_llm_async</code> 等具体实现。外层使用 <code>unwrap_caught_result</code> 包装 <code>dispatch_completion</code> 的 <code>kota::task</code>，将取消事件（<code>cancel</code>）统一转换为 <code>LLMError</code> 类型的失败结果。整个流程依赖 <code>kota::event_loop</code> 进行异步编排，并利用模板元函数 <code>detail::unwrap_caught_result</code> 捕获协程异常。</p><h4 id="side-effects" tabindex="-1">Side Effects <a class="header-anchor" href="#side-effects" aria-label="Permalink to &quot;Side Effects&quot;">​</a></h4><ul><li>Performs I/O to detect the LLM provider from environment variables</li><li>Makes network calls via <code>dispatch_completion</code> to communicate with the LLM API</li><li>Potentially handles cancellation, which may affect scheduling or resource cleanup</li></ul><h4 id="reads-from" tabindex="-1">Reads From <a class="header-anchor" href="#reads-from" aria-label="Permalink to &quot;Reads From&quot;">​</a></h4><ul><li>Environment variables (through <code>detect_provider_from_environment</code>)</li><li>The <code>CompletionRequest</code> parameter</li><li>The <code>kota::event_loop&amp;</code> parameter (for scheduling callbacks)</li></ul><h4 id="writes-to" tabindex="-1">Writes To <a class="header-anchor" href="#writes-to" aria-label="Permalink to &quot;Writes To&quot;">​</a></h4><ul><li>The coroutine return value (<code>kota::task::promise_type</code> state) via <code>co_return</code></li></ul><h4 id="usage-patterns" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>Called to perform an asynchronous LLM completion with automatic provider detection from environment</li><li>Typically used in async contexts that provide a <code>kota::event_loop</code></li></ul><h3 id="clore-net-call-llm-async" tabindex="-1"><code>clore::net::call_llm_async</code> <a class="header-anchor" href="#clore-net-call-llm-async" aria-label="Permalink to &quot;`clore::net::call_llm_async`&quot;">​</a></h3><p>Declaration: <code>network/network.cppm:18</code></p><p>Definition: <code>network/network.cppm:126</code></p><p>Declaration: <a href="./../../namespaces/clore/net/"><code>Namespace clore::net</code></a></p><p>函数 <code>clore::net::call_llm_async</code> 首先调用 <code>clore::net::(anonymous namespace)::detect_provider_from_environment</code> 来检测当前环境支持的 LLM 提供程序。如果检测失败，则通过 <code>kota::fail</code> 立即终止协程；否则，它将获取提供程序对应的标签，并将该标签、<code>model</code>、<code>system_prompt</code>、<code>request</code> 和 <code>loop</code> 传递给 <code>clore::net::(anonymous namespace)::request_provider_text_async</code>。实际的完成请求调度委托给一个 lambda 表达式，该表达式调用 <code>clore::net::(anonymous namespace)::dispatch_completion</code>，根据检测到的提供程序执行底层网络交互。整个流程依赖于 <code>RequestProviderTextAsync</code> 和 <code>dispatch_completion</code> 的异步协作，以及 <code>kota::event_loop</code> 提供的事件驱动调度。</p><h4 id="side-effects-1" tabindex="-1">Side Effects <a class="header-anchor" href="#side-effects-1" aria-label="Permalink to &quot;Side Effects&quot;">​</a></h4><ul><li>执行网络 I/O 调用 LLM API</li><li>读取环境变量以确定提供商</li></ul><h4 id="reads-from-1" tabindex="-1">Reads From <a class="header-anchor" href="#reads-from-1" aria-label="Permalink to &quot;Reads From&quot;">​</a></h4><ul><li><code>model</code></li><li><code>system_prompt</code></li><li><code>request</code></li><li><code>loop</code></li><li>环境变量（通过 <code>detect_provider_from_environment</code>）</li></ul><h4 id="writes-to-1" tabindex="-1">Writes To <a class="header-anchor" href="#writes-to-1" aria-label="Permalink to &quot;Writes To&quot;">​</a></h4><ul><li>返回的 <code>kota::task</code> 结果</li></ul><h4 id="usage-patterns-1" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-1" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>异步调用 LLM 生成文本</li><li>配合事件循环使用</li><li>错误处理通过 <code>LLMError</code></li></ul><h3 id="clore-net-validate-llm-provider-environment" tabindex="-1"><code>clore::net::validate_llm_provider_environment</code> <a class="header-anchor" href="#clore-net-validate-llm-provider-environment" aria-label="Permalink to &quot;`clore::net::validate_llm_provider_environment`&quot;">​</a></h3><p>Declaration: <code>network/network.cppm:28</code></p><p>Definition: <code>network/network.cppm:118</code></p><p>Declaration: <a href="./../../namespaces/clore/net/"><code>Namespace clore::net</code></a></p><p><code>clore::net::validate_llm_provider_environment</code> 的实现完全委托给 <code>detect_provider_from_environment</code>：它首先调用该函数获取一个 <code>std::expected</code> 结果，该结果表示环境中的 LLM 提供商配置是否有效。如果 <code>provider_result</code> 不持有值（即检测失败），函数立即返回一个 <code>std::unexpected</code> 包装的 <code>LLMError</code>；否则返回一个空的 <code>std::expected&lt;void, LLMError&gt;</code> 表示成功。整个控制流仅包含此单一分支，没有重试或附加验证逻辑，完全依赖 <code>detect_provider_from_environment</code> 内部对 <code>Provider</code> 枚举（如 <code>Provider::Anthropic</code> 和 <code>Provider::OpenAI</code>）以及对应环境变量（例如 <code>kAnthropicApiKeyEnv</code>、<code>kOpenAIApiKeyEnv</code>）的检查。</p><h4 id="side-effects-2" tabindex="-1">Side Effects <a class="header-anchor" href="#side-effects-2" aria-label="Permalink to &quot;Side Effects&quot;">​</a></h4><p>No observable side effects are evident from the extracted code.</p><h4 id="reads-from-2" tabindex="-1">Reads From <a class="header-anchor" href="#reads-from-2" aria-label="Permalink to &quot;Reads From&quot;">​</a></h4><ul><li>environment variables (via <code>detect_provider_from_environment</code>)</li></ul><h4 id="usage-patterns-2" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-2" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>Called before making LLM API calls to ensure provider is configured</li></ul><h2 id="internal-structure" tabindex="-1">Internal Structure <a class="header-anchor" href="#internal-structure" aria-label="Permalink to &quot;Internal Structure&quot;">​</a></h2><p><code>network</code> 模块以匿名命名空间隐藏内部实现，仅公开三个异步 LLM 调用接口。内部通过枚举 <code>Provider</code> 和一组环境变量常量（如 <code>kAnthropicApiKeyEnv</code>）进行提供者检测，<code>detect_provider_from_environment</code> 和 <code>has_nonempty_env</code> 等辅助函数负责解析运行环境；<code>dispatch_completion</code> 和模板函数 <code>request_provider_text_async</code> 封装了异步请求的分发与完成逻辑。公共接口 <code>validate_llm_provider_environment</code> 作为前置校验，<code>call_llm_async</code> 与 <code>call_completion_async</code> 向上层提供统一的异步调用入口，底层依赖 <code>kota::event_loop</code> 驱动事件循环，实现与控制流解耦。模块仅导入 <code>std</code>，无其他外部依赖。</p>',48)])])}const u=o(r,[["render",d]]);export{h as __pageData,u as default};
